  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = *conn_result;

    // 2. Create tables if they don't exist
    auto create_user_result = (sqlgen::create_table<User> | sqlgen::if_not_exists)(conn);
    if (!create_user_result) {
        throw std::runtime_error("Failed to create User table");
    }

    auto create_post_result = (sqlgen::create_table<Post> | sqlgen::if_not_exists)(conn);
    if (!create_post_result) {
        throw std::runtime_error("Failed to create Post table");
    }

    // 3. Build the query using sqlgen functions
    User user;
    Post post;

    auto query = sqlgen::select_from<User>(user.user_id, user.username)
                 | sqlgen::inner_join<Post>(post.user_id == user.user_id)
                 | sqlgen::where(post.created_at >= "2025-12-01" && post.created_at <= "2025-12-31")
                 | sqlgen::to<std::vector<ActiveUser>>;

    // 4. Execute the query and return results
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Failed to execute query");
    }

    return *result;
}

}  // namespace query_active_users_posts
```

