  auto conn = sqlgen::sqlite::connect("test_db.sqlite")
      .and_then(sqlgen::create_table<Course>)
      .and_then(sqlgen::create_table<Enrollment>);

  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  // 2. Build the query using sqlgen
  auto query = sqlgen::select_from<Course, "c">(
      "title"_t1,
      sqlgen::count("enrollment_id"_t2) | sqlgen::as<"student_count">,
      sqlgen::avg("grade"_t2) | sqlgen::as<"avg_grade">
    )
    | sqlgen::left_join<Enrollment, "e">("course_id"_t1 == "course_id"_t2)
    | sqlgen::group_by("title"_t1, "course_id"_t1)
    | sqlgen::to<std::vector<CourseStatsView>>;

  // 3. Execute the query and map results to CourseStats
  auto result = query(*conn);
  if (!result) {
