                           | sqlgen::where("account_id"_c == to_account_id))(conn);
    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
