namespace update_eas_table {

void update_eas_table() {
  design_eas_database_with_major();

  // 1. Add Grade column to Score table
  auto conn = sqlgen::sqlite::connect(db_path).value();
  conn->execute(R"(
    ALTER TABLE Score 
    ADD COLUMN Grade CHAR(1) NOT NULL
  )").value();

  // 2. Modify Age column in Student table to int with null allowed
  // First, create a new table with correct schema
  conn->execute(R"(
    CREATE TABLE Student_new (
      SNo VARCHAR(10) PRIMARY KEY,
      Name VARCHAR(30) NOT NULL,
      Sex INT NOT NULL,
      Birthday DATE,
      Major INT,
      Scores REAL DEFAULT 0.0,
      Remark TEXT,
      Age INT
    )
  )").value();

  // Copy data from old table to new table
  conn->execute(R"(
    INSERT INTO Student_new (SNo, Name, Sex, Birthday, Major, Scores, Remark, Age)
    SELECT SNo, Name, Sex, Birthday, Major, Scores, Remark, Age FROM Student
  )").value();

  // Drop old table and rename new table
  conn->execute(R"(
    DROP TABLE Student;
    ALTER TABLE Student_new RENAME TO Student;
  )").value();

  // 3. Drop Major table
  conn->execute("DROP TABLE IF EXISTS Major").value();
}

