          ("f4"_t6.user_id1 == "u2"_t5.user_id && "f4"_t6.user_id2 == "u1"_t1.user_id)
        ));

  // Query 4: Count friends per user and identify most connected users
  auto friend_count_query = sqlgen::read<std::vector<FriendConnection>>
      | sqlgen::select_from<User, "u">(sqlgen::col<"username">.as<"user1_name">())
      | sqlgen::left_join<Friendship, "f">("u"_t1.user_id == "f"_t2.user_id1)
