  combined_results.insert(combined_results.end(), friend_of_friend_results.begin(), friend_of_friend_results.end());
  combined_results.insert(combined_results.end(), friend_count_results.begin(), friend_count_results.end());
  combined_results.insert(combined_results.end(), recommendation_results.begin(), recommendation_results.end());

  return combined_results;
}

