  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  conn | sqlgen::create_table<Department> | sqlgen::create_table<Employee>;

  // Insert data
  conn | sqlgen::insert(depts) | sqlgen::insert(emps);

  // Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">("department_name"_t1)
                   | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
                   | sqlgen::select_from<Employee, "e">("first_name"_t2, "last_name"_t2, "salary"_t2)
                   | sqlgen::to<std::vector<JoinResult>>;

  // Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">("first_name"_t2, "last_name"_t2, "salary"_t2)
                  | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
                  | sqlgen::select_from<Department, "d">("department_name"_t1)
                  | sqlgen::to<std::vector<JoinResult>>;

  // Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Employee, "e">("first_name"_t2, "last_name"_t2, "salary"_t2)
                   | sqlgen::right_join<Department, "d">("department_id"_t2 == "department_id"_t1)
                   | sqlgen::select_from<Department, "d">("department_name"_t1)
                   | sqlgen::to<std::vector<JoinResult>>;

  // Perform FULL JOIN
  auto full_query = sqlgen::select_from<Employee, "e">("first_name"_t2, "last_name"_t2, "salary"_t2)
                  | sqlgen::full_join<Department, "d">("department_id"_t2 == "department_id"_t1)
                  | sqlgen::select_from<Department, "d">("department_name"_t1)
                  | sqlgen::to<std::vector<JoinResult>>;

  // Execute queries and populate results
  auto inner_result = inner_query(conn);
  auto left_result = left_query(conn);
  auto right_result = right_query(conn);
  auto full_result = full_query(conn);

  // Build and return analysis
  JoinAnalysis analysis{
      .inner_join_results = std::move(inner_result.value()),
      .left_join_results = std::move(left_result.value()),
      .right_join_results = std::move(right_result.value()),
      .full_join_results = std::move(full_result.value())
  };

  return analysis;
}

}  // namespace analyze_department_employees
```

