```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace concat_function {

struct Person {
  sqlgen::PrimaryKey<int> id;
  std::string first_name;
  std::string last_name;
};

struct FullName {
  std::string full_name;
};

/**
 * This function demonstrates CONCAT usage.
 * Returns: query value.
 */
inline auto concat_function() {
    using namespace sqlgen::literals;

    // Create the CONCAT expression: CONCAT(first_name, ' ', last_name)
    auto concat_expr = sqlgen::concat(
        "first_name"_c,
        " ",
        "last_name"_c
    );

    // Create the SELECT query using select_from<Person>
    auto query = sqlgen::select_from<Person>(concat_expr);

    // Alias the concatenated result to match the FullName struct field
    auto aliased_query = query | sqlgen::as<"full_name">;

    // Specify the return type as FullName
    return aliased_query | sqlgen::to<FullName>;
}

}  // namespace concat_function
```

**Explanation:**

1. **`sqlgen::select_from<Person>`**: Creates a SELECT query targeting the Person table
2. **`sqlgen::concat`**: Constructs the CONCAT function with three arguments:
   - `"first_name"_c`: Column reference using the string literal operator
   - `" "`: String literal for the space separator
   - `"last_name"_c`: Second column reference
3. **`sqlgen::as<"full_name">`**: Aliases the concatenated result to match the `full_name` field in the `FullName` struct
4. **`sqlgen::to<FullName>`**: Specifies that the query should return results mapped to the `FullName` struct

The function returns a query object that, when executed against a database connection, will return `FullName` objects containing the concatenated full names.

